    kv.set('purchase:buyer@example.com:test-book', JSON.stringify(purchase))

    const token = await signMagicToken(
      { email: 'buyer@example.com', bookSlug: 'test-book', exp: nowEpoch() + MAGIC_LINK_TTL },
