120→  onRestoreProgress,
121→  allChapters,
122→  bookBasePath,
123→  currentChapterSlug,
124→  offlineProps,
125→}: ScrollReaderProps) {
126→  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
127→
128→  // Footer visibility
129→  const [footerVisible, setFooterVisible] = useState(false);
130→  const footerTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
131→  const [settingsOpen, setSettingsOpen] = useState(false);
132→  const [tocOpen, setTocOpen] = useState(false);
133→
134→  const showFooterTemporarily = useCallback(() => {
135→    setFooterVisible(true);
136→    if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
137→    footerTimerRef.current = setTimeout(() => setFooterVisible(false), 3000);
138→  }, []);
139→
140→  // Settings state
141→  const [activeTheme, setActiveTheme] = useState<string>(() => {
142→    if (typeof localStorage !== "undefined") {
143→      return localStorage.getItem("pressy-theme") || "light";
144→    }
145→    return "light";
146→  });
147→  const [fontScale, setFontScale] = useState<number>(() => {
148→    if (typeof localStorage !== "undefined") {
149→      const saved = localStorage.getItem("pressy-font-size");
150→      return saved ? parseFloat(saved) : 1.0;
151→    }
152→    return 1.0;
153→  });
154→
155→  const applyFontScale = useCallback((scale: number) => {
156→    if (scale === 1.0) {
157→      document.documentElement.style.removeProperty("--font-size-base");
158→    } else {
159→      document.documentElement.style.setProperty(
160→        "--font-size-base",
161→        `calc(clamp(1rem, 0.875rem + 0.5vw, 1.25rem) * ${scale})`
162→      );
163→    }
164→  }, []);
165→
166→  useEffect(() => {
167→    if (fontScale !== 1.0) {
168→      applyFontScale(fontScale);
169→    }
170→  }, []);
171→
172→  const handleThemeChange = useCallback((theme: string) => {
173→    setActiveTheme(theme);
174→    localStorage.setItem("pressy-theme", theme);
175→    const resolved =
176→      theme === "system"
177→        ? window.matchMedia("(prefers-color-scheme: dark)").matches
178→          ? "dark"
