 35→async function initDB(): Promise<IDBDatabase> {
 36→  if (db) return db
 37→
 38→  return new Promise((resolve, reject) => {
 39→    const request = indexedDB.open(DB_NAME, DB_VERSION)
 40→
 41→    request.onerror = () => reject(request.error)
 42→    request.onsuccess = () => {
 43→      db = request.result
 44→      resolve(db)
 45→    }
 46→
 47→    request.onupgradeneeded = (event) => {
 48→      const database = (event.target as IDBOpenDBRequest).result
 49→      if (!database.objectStoreNames.contains(PROGRESS_STORE)) {
 50→        database.createObjectStore(PROGRESS_STORE, { keyPath: 'chapterSlug' })
 51→      }
 52→      if (!database.objectStoreNames.contains(UNLOCKS_STORE)) {
 53→        database.createObjectStore(UNLOCKS_STORE, { keyPath: 'bookSlug' })
 54→      }
 55→    }
 56→  })
 57→}
