 59→export async function saveReadingProgress(progress: ReadingProgress): Promise<void> {
 60→  const database = await initDB()
 61→  return new Promise((resolve, reject) => {
 62→    const tx = database.transaction(PROGRESS_STORE, 'readwrite')
 63→    const store = tx.objectStore(PROGRESS_STORE)
 64→    const request = store.put(progress)
 65→    request.onsuccess = () => resolve()
 66→    request.onerror = () => reject(request.error)
 67→  })
 68→}
