 70→export async function getReadingProgress(chapterSlug: string): Promise<ReadingProgress | null> {
 71→  const database = await initDB()
 72→  return new Promise((resolve, reject) => {
 73→    const tx = database.transaction(PROGRESS_STORE, 'readonly')
 74→    const store = tx.objectStore(PROGRESS_STORE)
 75→    const request = store.get(chapterSlug)
 76→    request.onsuccess = () => resolve(request.result || null)
 77→    request.onerror = () => reject(request.error)
 78→  })
 79→}
