 81→export async function getAllReadingProgress(): Promise<ReadingProgress[]> {
 82→  const database = await initDB()
 83→  return new Promise((resolve, reject) => {
 84→    const tx = database.transaction(PROGRESS_STORE, 'readonly')
 85→    const store = tx.objectStore(PROGRESS_STORE)
 86→    const request = store.getAll()
 87→    request.onsuccess = () => resolve(request.result || [])
 88→    request.onerror = () => reject(request.error)
 89→  })
 90→}
