 92→export async function isBookUnlocked(bookSlug: string): Promise<boolean> {
 93→  const database = await initDB()
 94→  return new Promise((resolve, reject) => {
 95→    const tx = database.transaction(UNLOCKS_STORE, 'readonly')
 96→    const store = tx.objectStore(UNLOCKS_STORE)
 97→    const request = store.get(bookSlug)
 98→    request.onsuccess = () => resolve(!!request.result)
 99→    request.onerror = () => reject(request.error)
100→  })
101→}
