103→export async function unlockBook(bookSlug: string, orderId?: string): Promise<void> {
104→  const database = await initDB()
105→  return new Promise((resolve, reject) => {
106→    const tx = database.transaction(UNLOCKS_STORE, 'readwrite')
107→    const store = tx.objectStore(UNLOCKS_STORE)
108→    const request = store.put({ bookSlug, orderId, unlockedAt: Date.now() })
109→    request.onsuccess = () => resolve()
110→    request.onerror = () => reject(request.error)
111→  })
112→}
