143→
144→  // Listen for OS theme changes so "system" mode updates live
145→  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', () => {
146→    if (currentTheme.value === 'system') {
147→      document.documentElement.setAttribute('data-theme', resolveSystemTheme())
148→    }
149→  })
150→}
