 10→// ── Offline Footer Icon ───────────────────────────────────────
 11→
 12→export function OfflineFooterIcon({ offlineProps }: { offlineProps?: OfflineProps }) {
 13→  if (!offlineProps) return null;
 14→
 15→  const {
 16→    bookSlug,
 17→    chapterUrls,
 18→    cachedBooks,
 19→    onDownload,
 20→    onRemove,
 21→  } = offlineProps;
 22→
 23→  // Read signal .value directly in render — @preact/signals auto-subscribes
 24→  // and re-renders this component when the underlying signal changes.
 25→  const isCached = cachedBooks.value.has(bookSlug);
 26→
 27→  // Check isCached FIRST (matching DownloadBook's order). The download function
 28→  // optimistically marks the book as cached immediately, so isCached becomes true
 29→  // at the same time as isDownloading. Checking isCached first means we show the
 30→  // cached icon right away while the SW downloads in the background.
 31→  if (isCached) {
 32→    return (
 33→      <button
 34→        class="pressy-offline-icon pressy-offline-icon--cached"
 35→        onClick={(e: MouseEvent) => {
 36→          e.stopPropagation();
 37→          onRemove(bookSlug);
 38→        }}
 39→        aria-label="Available offline. Click to remove."
 40→        title="Available offline. Click to remove."
 41→      >
 42→        <svg
 43→          viewBox="0 0 24 24"
 44→          fill="none"
 45→          stroke="currentColor"
 46→          stroke-width="1.5"
 47→          stroke-linecap="round"
 48→          stroke-linejoin="round"
 49→          width="18"
 50→          height="18"
 51→        >
 52→          <path d="M18 10h-1.26A8 8 0 1 0 9 20h9a5 5 0 0 0 0-10z" />
 53→          <polyline points="9 15 12 18 15 15" />
 54→          <line x1="12" y1="12" x2="12" y2="18" />
 55→        </svg>
 56→        <svg
 57→          class="pressy-offline-check"
 58→          viewBox="0 0 24 24"
 59→          fill="currentColor"
 60→          width="10"
 61→          height="10"
 62→        >
 63→          <path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41L9 16.17z" />
 64→        </svg>
 65→      </button>
