  1→import { ComponentChildren, ComponentType } from "preact";
  2→import { useState, useEffect, useRef, useCallback } from "preact/hooks";
  3→
  4→import { TextShare } from "../TextShare.js";
  5→import { OfflineIndicator } from "../OfflineIndicator.js";
  6→import { OfflineFooterIcon } from "./ScrollReader.js";
  7→import { PAGINATED_STYLES } from "./paginated-reader-styles.js";
  8→import type { ProgressData, ChapterMapData, OfflineProps, ReaderPaywallConfig } from "./types.js";
  9→
 10→// ── Paginated Reader ──────────────────────────────────────────
 11→
 12→interface LoadedChapter {
 13→  slug: string;
 14→  title: string;
 15→  Content: ComponentType<{ components?: Record<string, unknown> }>;
 16→}
 17→
 18→interface ChapterPageRange {
 19→  slug: string;
 20→  startPage: number;
 21→  endPage: number;
 22→}
 23→
 24→export interface PaginatedReaderProps {
 25→  children: ComponentChildren;
 26→  bookTitle?: string;
 27→  prevChapter?: { slug: string; title: string };
 28→  nextChapter?: { slug: string; title: string };
 29→  showDropCap: boolean;
 30→  onSaveProgress?: (data: ProgressData) => void;
 31→  onRestoreProgress?: () => Promise<ProgressData | null>;
 32→  bookProgressPercent?: number;
 33→  initialContent?: ComponentType<{ components?: Record<string, unknown> }>;
 34→  chapterMapData?: ChapterMapData;
 35→  currentChapterSlug?: string;
 36→  allChapters?: Array<{ slug: string; title: string; wordCount?: number }>;
 37→  bookBasePath?: string;
 38→  onChapterChange?: (slug: string, page: number, totalPages: number) => void;
 39→  mdxComponents?: Record<string, unknown>;
 40→  paywall?: ReaderPaywallConfig;
 41→  offlineProps?: OfflineProps;
 42→}
 43→
 44→function ChapterDivider({ title }: { title: string }) {
 45→  return (
 46→    <div class="pressy-chapter-divider">
 47→      <h2 class="pressy-chapter-divider-title">{title}</h2>
 48→    </div>
 49→  );
