 52→export function PaginatedReader({
 53→  children,
 54→  bookTitle,
 55→  prevChapter,
 56→  nextChapter,
 57→  showDropCap,
 58→  onSaveProgress,
 59→  onRestoreProgress,
 60→  bookProgressPercent,
 61→  initialContent,
 62→  chapterMapData,
 63→  currentChapterSlug,
 64→  allChapters,
 65→  bookBasePath,
 66→  onChapterChange,
 67→  mdxComponents,
 68→  paywall,
 69→  offlineProps,
 70→}: PaginatedReaderProps) {
 71→  const containerRef = useRef<HTMLDivElement>(null);
 72→  const viewportRef = useRef<HTMLDivElement>(null);
 73→  const articleRef = useRef<HTMLElement>(null);
 74→  const [currentPage, setCurrentPage] = useState(0);
 75→  const [totalPages, setTotalPages] = useState(1);
 76→  const totalPagesRef = useRef(1);
 77→  totalPagesRef.current = totalPages;
 78→  const [pagesReady, setPagesReady] = useState(false);
 79→  const hasRestoredRef = useRef(false);
 80→  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 81→  const skipTransitionRef = useRef(false);
 82→
 83→  // Detect ?page=last on initial render (backward chapter navigation)
 84→  const wantsLastPageRef = useRef(
 85→    typeof window !== "undefined" &&
 86→      new URLSearchParams(window.location.search).get("page") === "last"
 87→  );
 88→  // Hide content until page position is resolved (prevents flash at page 0
 89→  // before jumping to the saved page). Covers both ?page=last and normal restore.
 90→  const [awaitingRestore, setAwaitingRestore] = useState(
 91→    wantsLastPageRef.current || !!onRestoreProgress
 92→  );
 93→
 94→  // Multi-chapter state
 95→  const [loadedChapters, setLoadedChapters] = useState<LoadedChapter[]>([]);
 96→  const [chapterRanges, setChapterRanges] = useState<ChapterPageRange[]>([]);
 97→  const [activeChapterSlug, setActiveChapterSlug] = useState(
 98→    currentChapterSlug || ""
 99→  );
100→  const preloadingRef = useRef<Set<string>>(new Set());
101→
102→  // Whether we're in multi-chapter mode
103→  const isMultiChapter = !!(
104→    chapterMapData &&
105→    initialContent &&
106→    currentChapterSlug &&
107→    allChapters
108→  );
109→
110→  // Initialize loaded chapters
111→  useEffect(() => {
112→    if (isMultiChapter && initialContent && currentChapterSlug) {
113→      const chapterInfo = allChapters!.find(
114→        (ch) => ch.slug === currentChapterSlug
115→      );
116→      setLoadedChapters([
117→        {
118→          slug: currentChapterSlug,
119→          title: chapterInfo?.title || currentChapterSlug,
120→          Content: initialContent,
121→        },
122→      ]);
123→      setActiveChapterSlug(currentChapterSlug);
124→    }
125→  }, []); // Only on mount
126→
127→  // Clean up ?page=last from the URL on mount
128→  useEffect(() => {
129→    if (wantsLastPageRef.current) {
130→      const url = new URL(window.location.href);
131→      url.searchParams.delete("page");
132→      history.replaceState(null, "", url.pathname);
133→    }
134→  }, []);
135→
136→  // Settings & TOC panel state
137→  const [settingsOpen, setSettingsOpen] = useState(false);
138→  const [tocOpen, setTocOpen] = useState(false);
139→  const [activeTheme, setActiveTheme] = useState<string>(() => {
140→    if (typeof localStorage !== "undefined") {
141→      return localStorage.getItem("pressy-theme") || "light";
142→    }
143→    return "light";
144→  });
145→  const [fontScale, setFontScale] = useState<number>(() => {
146→    if (typeof localStorage !== "undefined") {
147→      const saved = localStorage.getItem("pressy-font-size");
148→      return saved ? parseFloat(saved) : 1.0;
149→    }
150→    return 1.0;
151→  });
152→
153→  const applyFontScale = useCallback((scale: number) => {
154→    if (scale === 1.0) {
155→      document.documentElement.style.removeProperty("--font-size-base");
156→    } else {
157→      document.documentElement.style.setProperty(
158→        "--font-size-base",
159→        `calc(clamp(1rem, 0.875rem + 0.5vw, 1.25rem) * ${scale})`
160→      );
161→    }
162→  }, []);
163→
164→  // Apply saved font scale on mount
165→  useEffect(() => {
166→    if (fontScale !== 1.0) {
167→      applyFontScale(fontScale);
168→    }
169→  }, []);
170→
171→  // Sync real viewport height to CSS custom property.
172→  // 100dvh is unreliable on Android PWAs where the system nav bar
173→  // overlaps the content. window.innerHeight always reflects the
174→  // actual usable area.
175→  useEffect(() => {
176→    const container = containerRef.current;
177→    if (!container) return;
178→
179→    const syncHeight = () => {
180→      container.style.setProperty("--app-height", `${window.innerHeight}px`);
181→    };
182→    syncHeight();
183→
184→    window.addEventListener("resize", syncHeight);
185→    window.visualViewport?.addEventListener("resize", syncHeight);
186→    return () => {
187→      window.removeEventListener("resize", syncHeight);
188→      window.visualViewport?.removeEventListener("resize", syncHeight);
189→    };
190→  }, []);
191→
192→  const handleThemeChange = useCallback((theme: string) => {
193→    setActiveTheme(theme);
194→    localStorage.setItem("pressy-theme", theme);
195→    const resolved =
196→      theme === "system"
197→        ? window.matchMedia("(prefers-color-scheme: dark)").matches
198→          ? "dark"
199→          : "light"
200→        : theme;
201→    document.documentElement.setAttribute("data-theme", resolved);
202→  }, []);
203→
204→  // Drag/swipe state
205→  const [isDragging, setIsDragging] = useState(false);
206→  const [dragOffset, setDragOffset] = useState(0);
207→  const [chapterHint, setChapterHint] = useState<"next" | "prev" | null>(null);
208→
209→  // Touch tracking refs (avoid re-renders during drag)
210→  const touchStartXRef = useRef(0);
211→  const touchStartYRef = useRef(0);
212→  const lastTouchXRef = useRef(0);
213→  const lastTouchTimeRef = useRef(0);
214→  const velocityRef = useRef(0);
215→  const isSwipingRef = useRef(false);
216→  const isDraggingRef = useRef(false);
217→
218→  // Build page-to-chapter map after recalculating pages
219→  const updateChapterRanges = useCallback(() => {
220→    if (!isMultiChapter) return;
221→    const article = articleRef.current;
222→    const viewport = viewportRef.current;
223→    if (!article || !viewport) return;
224→
225→    const viewportWidth = viewport.clientWidth;
226→    if (viewportWidth === 0) return;
227→
228→    const sections = article.querySelectorAll(".pressy-chapter-section");
229→    const ranges: ChapterPageRange[] = [];
230→
231→    sections.forEach((section) => {
232→      const slug = section.getAttribute("data-chapter-slug") || "";
233→      const sectionLeft = (section as HTMLElement).offsetLeft;
234→      const sectionWidth = (section as HTMLElement).scrollWidth;
235→      const startPage = Math.floor(sectionLeft / viewportWidth);
236→      const endPage = Math.max(
237→        startPage,
238→        Math.ceil((sectionLeft + sectionWidth) / viewportWidth) - 1
239→      );
240→      ranges.push({ slug, startPage, endPage });
241→    });
242→
243→    setChapterRanges(ranges);
244→  }, [isMultiChapter]);
245→
246→  // Calculate page count and set column-width to match viewport
247→  const recalculatePages = useCallback(() => {
248→    const article = articleRef.current;
249→    const viewport = viewportRef.current;
250→    if (!article || !viewport) return;
251→
252→    const viewportWidth = viewport.clientWidth;
253→    if (viewportWidth === 0) return;
254→
255→    // Set column-width to viewport width so each column = one page
256→    article.style.columnWidth = `${viewportWidth}px`;
257→
258→    // Force synchronous layout recalculation
259→    void article.scrollWidth;
260→
261→    const total = Math.max(1, Math.round(article.scrollWidth / viewportWidth));
262→    setTotalPages(total);
263→    setPagesReady(true);
264→
265→    // Clamp current page if now out of bounds (e.g. after resize)
266→    setCurrentPage((prev) => Math.min(prev, total - 1));
267→
268→    // Update chapter ranges for multi-chapter mode
269→    updateChapterRanges();
270→  }, [updateChapterRanges]);
271→
272→  // Font size change handler (defined after recalculatePages)
273→  const handleFontSizeChange = useCallback(
274→    (delta: number) => {
275→      setFontScale((prev) => {
276→        const next =
277→          Math.round(Math.max(0.8, Math.min(1.5, prev + delta)) * 10) / 10;
278→        localStorage.setItem("pressy-font-size", String(next));
279→        applyFontScale(next);
280→        setTimeout(() => recalculatePages(), 100);
281→        return next;
282→      });
283→    },
284→    [applyFontScale, recalculatePages]
285→  );
286→
287→  // Recalculate on mount and on resize via ResizeObserver
288→  useEffect(() => {
289→    const viewport = viewportRef.current;
290→    if (!viewport) return;
291→
292→    // Delay initial calculation to let fonts and content render
293→    const initialTimer = setTimeout(recalculatePages, 50);
294→
295→    const observer = new ResizeObserver(() => {
296→      recalculatePages();
297→    });
298→    observer.observe(viewport);
299→
300→    return () => {
301→      clearTimeout(initialTimer);
302→      observer.disconnect();
303→    };
304→  }, [recalculatePages]);
305→
306→  // Recalculate when loaded chapters change
307→  useEffect(() => {
308→    if (loadedChapters.length > 0) {
309→      // Delay to let new content render
310→      const timer = setTimeout(recalculatePages, 50);
311→      return () => clearTimeout(timer);
312→    }
313→  }, [loadedChapters.length, recalculatePages]);
314→
315→  // Recalculate when images finish loading
316→  useEffect(() => {
317→    const article = articleRef.current;
318→    if (!article) return;
319→
320→    const images = article.querySelectorAll("img");
321→    if (images.length === 0) return;
322→
323→    const onLoad = () => recalculatePages();
324→    images.forEach((img) => {
325→      if (!img.complete) {
326→        img.addEventListener("load", onLoad);
327→        img.addEventListener("error", onLoad);
328→      }
329→    });
330→
331→    return () => {
332→      images.forEach((img) => {
333→        img.removeEventListener("load", onLoad);
334→        img.removeEventListener("error", onLoad);
335→      });
336→    };
337→  }, [recalculatePages, loadedChapters.length]);
338→
339→  // Restore page position once pages are first computed.
340→  // Handles both ?page=last (backward chapter nav) and normal restore from
341→  // localStorage in a single effect — no racing between separate effects.
342→  // Uses pagesReady (not totalPages > 1) so single-page chapters work too.
343→  useEffect(() => {
344→    if (hasRestoredRef.current || !pagesReady) return;
345→
346→    // 1. ?page=last takes priority (backward chapter navigation)
347→    if (wantsLastPageRef.current) {
348→      wantsLastPageRef.current = false;
349→      skipTransitionRef.current = true;
350→      setCurrentPage(totalPages - 1);
351→      hasRestoredRef.current = true;
352→      setAwaitingRestore(false);
353→      return;
354→    }
355→
356→    // 2. Try to restore from saved progress
357→    if (!onRestoreProgress) {
358→      hasRestoredRef.current = true;
359→      setAwaitingRestore(false);
360→      return;
361→    }
362→
363→    onRestoreProgress().then((data) => {
364→      if (hasRestoredRef.current) {
365→        setAwaitingRestore(false);
366→        return;
367→      }
368→
369→      const currentTotalPages = totalPagesRef.current;
370→
371→      if (!data || data.page <= 0) {
372→        hasRestoredRef.current = true;
373→        setAwaitingRestore(false);
374→        return;
375→      }
376→
377→      let targetPage: number;
378→      if (
379→        data.totalPages <= 1 ||
380→        Math.abs(data.totalPages - currentTotalPages) <= 2
381→      ) {
382→        // Saved totalPages is degenerate (<=1) or very close to current —
383→        // use saved page directly. Clamping below handles out-of-bounds.
384→        targetPage = data.page;
385→      } else {
386→        // Significantly different layout — scale proportionally
387→        const fraction = data.page / (data.totalPages - 1);
388→        targetPage = Math.round(fraction * (currentTotalPages - 1));
389→      }
390→
391→      const clamped = Math.max(
392→        0,
393→        Math.min(targetPage, currentTotalPages - 1)
394→      );
395→      skipTransitionRef.current = true;
396→      setCurrentPage(clamped);
397→      hasRestoredRef.current = true;
398→      setAwaitingRestore(false);
399→    });
400→  }, [pagesReady, totalPages, onRestoreProgress]);
401→
402→  // Apply translateX — combines page position + drag offset
403→  useEffect(() => {
404→    const article = articleRef.current;
405→    const viewport = viewportRef.current;
406→    if (!article || !viewport) return;
407→
408→    const baseOffset = currentPage * viewport.clientWidth;
409→    const totalOffset = baseOffset - dragOffset;
410→
411→    if (isDragging || skipTransitionRef.current) {
412→      // During drag or programmatic restore: no transition, immediate response
413→      article.style.transition = "none";
414→      skipTransitionRef.current = false;
415→    } else {
416→      // Snap animation: smooth ease-out
417→      article.style.transition =
418→        "transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94)";
419→    }
420→
421→    article.style.transform = `translateX(-${totalOffset}px)`;
422→  }, [currentPage, dragOffset, isDragging]);
423→
424→  // Manage focusability: elements on off-screen pages get tabindex="-1"
425→  // so tab navigation can't reach them and cause layout shifts.
426→  // Uses getBoundingClientRect which accounts for the CSS transform.
427→  useEffect(() => {
428→    const article = articleRef.current;
429→    const viewport = viewportRef.current;
430→    if (!article || !viewport) return;
431→
432→    const viewportRect = viewport.getBoundingClientRect();
433→
434→    const focusable = article.querySelectorAll<HTMLElement>(
435→      "a[href], button, input, select, textarea, [tabindex]"
436→    );
437→
438→    focusable.forEach((el) => {
439→      const elRect = el.getBoundingClientRect();
440→      const onCurrentPage =
441→        elRect.left >= viewportRect.left - 1 &&
442→        elRect.right <= viewportRect.right + 1;
443→
444→      if (onCurrentPage) {
445→        const original = el.getAttribute("data-original-tabindex");
446→        if (original !== null) {
447→          if (original === "") {
448→            el.removeAttribute("tabindex");
449→          } else {
450→            el.setAttribute("tabindex", original);
451→          }
452→          el.removeAttribute("data-original-tabindex");
453→        }
454→      } else {
455→        if (!el.hasAttribute("data-original-tabindex")) {
456→          el.setAttribute(
457→            "data-original-tabindex",
458→            el.getAttribute("tabindex") || ""
459→          );
460→        }
461→        el.setAttribute("tabindex", "-1");
462→      }
463→    });
464→  }, [currentPage, totalPages]);
465→
466→  // Preload next chapter when within 2 pages of chapter end
467→  useEffect(() => {
468→    if (!isMultiChapter || !chapterMapData || chapterRanges.length === 0)
469→      return;
470→
471→    const activeRange = chapterRanges.find((r) => r.slug === activeChapterSlug);
472→    if (!activeRange) return;
473→
474→    const pagesFromEnd = activeRange.endPage - currentPage;
475→    if (pagesFromEnd > 2) return;
476→
477→    // Find the next chapter to preload
478→    const { chapterOrder, chapterMap } = chapterMapData;
479→    const lastLoadedSlug = loadedChapters[loadedChapters.length - 1]?.slug;
480→    const lastLoadedIdx = chapterOrder.indexOf(lastLoadedSlug);
481→    if (lastLoadedIdx === -1 || lastLoadedIdx >= chapterOrder.length - 1)
