  class="pressy-toc-toggle"
  onClick={(e: MouseEvent) => {
    e.stopPropagation();
    setSettingsOpen(false);    // Close settings when opening TOC
    setTocOpen(!tocOpen);
  }}
/>
```

---

### 4. FOOTER VISIBILITY AND SETTINGS INTERACTION

#### ScrollReader footer container (lines 367-372)
```jsx
<div
  class={`pressy-page-footer pressy-page-footer--scroll ${
    footerVisible || settingsOpen || tocOpen
      ? "pressy-page-footer--visible"
      : ""
  }`}
>
```

#### PaginatedReader footer container (lines 1292-1297)
```jsx
<div
  class={`pressy-page-footer ${
    footerVisible || settingsOpen || tocOpen
      ? "pressy-page-footer--visible"
      : ""
  }`}
>
```

**Key Behavior:**
- **Footer stays visible when settings is open** - the footer class adds `--visible` if any of: `footerVisible`, `settingsOpen`, or `tocOpen` is true
- This prevents the auto-hide timer from dismissing the footer while settings panel is open
- The footer remains fixed at bottom (z-index: 15) and settings panel expands upward from it

#### Footer auto-hide timer (both readers)
**ScrollReader (lines 134-138):**
```typescript
const showFooterTemporarily = useCallback(() => {
  setFooterVisible(true);
  if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
  footerTimerRef.current = setTimeout(() => setFooterVisible(false), 3000);
}, []);
```

**PaginatedReader (lines 733-737):**
```typescript
const showFooterTemporarily = useCallback(() => {
  setFooterVisible(true);
  if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
  footerTimerRef.current = setTimeout(() => setFooterVisible(false), 3000);
}, []);
```

**The Footer stays open while settings is active** - but the timer is NOT explicitly cancelled when settings opens. Instead, the footer visibility is maintained through the conditional class.

---

### 5. CSS ANIMATION/TRANSITION STYLES

#### Scroll Reader styles (lines 87-101 in scroll-reader-styles.ts)
```css
.pressy-page-footer--scroll .pressy-settings-panel {
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  transition: max-height 0.25s ease, opacity 0.2s ease;
  border-top: 0 solid var(--color-border, #dee2e6);
}

.pressy-page-footer--scroll .pressy-settings-panel--open {
  max-height: 300px;
  opacity: 1;
  border-top-width: 1px;
  margin-top: 0.5rem;
  padding-top: 0.75rem;
}
```

#### Paginated Reader styles (lines 265-279 in paginated-reader-styles.ts)
```css
.pressy-settings-panel {
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  transition: max-height 0.25s ease, opacity 0.2s ease;
  border-top: 0 solid var(--color-border, #dee2e6);
}

.pressy-settings-panel--open {
  max-height: 300px;
  opacity: 1;
  border-top-width: 1px;
  margin-top: 0.5rem;
  padding-top: 0.75rem;
}
```

**Animation mechanics:**
- **Closed state:** `max-height: 0` with `overflow: hidden` clips the panel
- **Open state:** `max-height: 300px` allows the panel to expand
- **Both properties transition:** `max-height 0.25s ease` and `opacity 0.2s ease`
- **Border animation:** Top border width animates from 0 to 1px on open
- **Spacing:** Margin-top and padding-top add when opened

The `max-height: 300px` is a conservative value to ensure the panel fits on small screens while the actual content may be smaller.

---

### 6. CLICK HANDLER CLOSING BEHAVIOR

#### ScrollReader click handler (lines 198-224)
```typescript
const handleReaderClick = useCallback(
  (e: MouseEvent) => {
    const target = e.target as HTMLElement;
    // Skip clicks on footer/TOC elements
    if (
      target.closest(
        ".pressy-page-footer, .pressy-toc-backdrop, .pressy-toc-toggle"
      )
    )
      return;
    if (target.closest('a, button, input, select, textarea, [role="button"]'))
      return;

    // If settings or TOC panel is open, close it on any outside click
    if (settingsOpen || tocOpen) {
      setSettingsOpen(false);
      setTocOpen(false);
      return;
    }

    // ... rest of logic (footer toggle, etc)
  },
  [footerVisible, settingsOpen, tocOpen, showFooterTemporarily]
);
```

#### PaginatedReader click handler (lines 763-841)
```typescript
const handleContainerClick = useCallback(
  (e: MouseEvent) => {
    const target = e.target as HTMLElement;

    // Clicks inside panels or on interactive elements — ignore
    if (
      target.closest(
        ".pressy-settings-panel, .pressy-settings-toggle, .pressy-toc-drawer, .pressy-toc-toggle"
      )
    )
      return;
    if (target.closest('a, button, input, select, textarea, [role="button"]'))
      return;

    // If settings or TOC panel is open, close it on any outside click
    if (settingsOpen || tocOpen) {
      setSettingsOpen(false);
      setTocOpen(false);
      return;
    }

    // ... rest of logic (page navigation on touch devices, etc)
  },
  [
    goNext,
    goPrev,
    footerVisible,
    isTouchDevice,
    settingsOpen,
    tocOpen,
    showFooterTemporarily,
    toggleFullscreen,
  ]
);
```

**Key difference:** 
- **ScrollReader** excludes `.pressy-page-footer` from triggering close (allows clicking in footer area)
- **PaginatedReader** explicitly checks for `.pressy-settings-panel, .pressy-settings-toggle` to prevent close

Both readers close settings/TOC on outside clicks except for:
1. Clicks on the panels themselves
2. Clicks on buttons/links inside the panels
3. Clicks on toggle buttons (they handle their own state)

---

### 7. READERPROPS INTERFACE (client.tsx perspective)

From `/Users/blittle/dev/pressy3/packages/@pressy/components/src/Reader.tsx` (lines 8-29):

```typescript
export interface ReaderProps {
  children: ComponentChildren;
  title: string;
  bookTitle?: string;
  chapterSlug?: string;
  prevChapter?: { slug: string; title: string };
  nextChapter?: { slug: string; title: string };
  showDropCap?: boolean;
  paginationMode?: "scroll" | "paginated";
  onSaveProgress?: (data: import("./reader/types.js").ProgressData) => void;
  onRestoreProgress?: () => Promise<import("./reader/types.js").ProgressData | null>;
  bookProgressPercent?: number;
  initialContent?: ComponentType<{ components?: Record<string, unknown> }>;
  chapterMapData?: import("./reader/types.js").ChapterMapData;
  currentChapterSlug?: string;
  allChapters?: Array<{ slug: string; title: string; wordCount?: number }>;
  bookBasePath?: string;
  onChapterChange?: (slug: string, page: number, totalPages: number) => void;
  mdxComponents?: Record<string, unknown>;
  paywall?: import("./reader/types.js").ReaderPaywallConfig;
  offlineProps?: import("./reader/types.js").OfflineProps;
