const handleSaveProgress = (data: ProgressData) => {
  const saveSlug = data.activeChapterSlug || chapterSlug

  // 1. Synchronous localStorage write (source of truth for position restore)
  localStorage.setItem('pressy-last-read', JSON.stringify({
    bookSlug: book.slug,
    chapterSlug: saveSlug,
    page: data.page,
    totalPages: data.totalPages,
    scrollPosition: data.scrollPosition,
  }))

  // 2. Async IndexedDB write (used for progress calculation)
  saveReadingProgress({
    chapterSlug: saveSlug,
    page: data.page,
    totalPages: data.totalPages,
    scrollPosition: data.scrollPosition,
    timestamp: Date.now(),
  })

  // 3. Recompute global book progress
  if (data.totalPages > 0) {
    getAllReadingProgress().then((allProgress) => {
      const percent = calculateBookProgressPercent(
        book, saveSlug, data.page, data.totalPages, allProgress,
      )
      setBookProgressPercent(percent)
    })
  }
}
```

**Key Pattern for Bookmarks:**
- Save to IndexedDB should be non-blocking (async)
- localStorage can be for quick access, IndexedDB for persistent history
- Callbacks should update UI state after successful persistence

