## 1. **Database Initialization Pattern** (`client.tsx` lines 27-57)

```typescript
// Constants
const DB_NAME = 'pressy'
const DB_VERSION = 1
const PROGRESS_STORE = 'reading-progress'
const UNLOCKS_STORE = 'unlocks'

// Global DB reference
let db: IDBDatabase | null = null

// Initialization function
async function initDB(): Promise<IDBDatabase> {
  if (db) return db

  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION)

    request.onerror = () => reject(request.error)
    request.onsuccess = () => {
      db = request.result
      resolve(db)
    }

    request.onupgradeneeded = (event) => {
      const database = (event.target as IDBOpenDBRequest).result
      if (!database.objectStoreNames.contains(PROGRESS_STORE)) {
        database.createObjectStore(PROGRESS_STORE, { keyPath: 'chapterSlug' })
      }
      if (!database.objectStoreNames.contains(UNLOCKS_STORE)) {
        database.createObjectStore(UNLOCKS_STORE, { keyPath: 'bookSlug' })
      }
    }
  })
}
```

**Key Points:**
- Single global `db` instance (lazy-initialized)
- `DB_VERSION = 1` — for adding new stores, you must **increment this version**
- `onupgradeneeded` is where you **add new object stores**
- Each store has a `keyPath` (primary key) — for `reading-progress` it's `chapterSlug`, for `unlocks` it's `bookSlug`

