172→  const handleThemeChange = useCallback((theme: string) => {
173→    setActiveTheme(theme);
174→    localStorage.setItem("pressy-theme", theme);
175→    const resolved =
176→      theme === "system"
177→        ? window.matchMedia("(prefers-color-scheme: dark)").matches
178→          ? "dark"
179→          : "light"
180→        : theme;
181→    document.documentElement.setAttribute("data-theme", resolved);
182→  }, []);
183→
184→  const handleFontSizeChange = useCallback(
185→    (delta: number) => {
186→      setFontScale((prev) => {
187→        const next =
188→          Math.round(Math.max(0.8, Math.min(1.5, prev + delta)) * 10) / 10;
189→        localStorage.setItem("pressy-font-size", String(next));
190→        applyFontScale(next);
191→        return next;
192→      });
193→    },
194→    [applyFontScale]
195→  );
196→
197→  // Toggle footer on tap
198→  const handleReaderClick = useCallback(
199→    (e: MouseEvent) => {
200→      const target = e.target as HTMLElement;
201→      if (
202→        target.closest(
203→          ".pressy-page-footer, .pressy-toc-backdrop, .pressy-toc-toggle"
204→        )
205→      )
206→        return;
207→      if (target.closest('a, button, input, select, textarea, [role="button"]'))
208→        return;
209→
210→      if (settingsOpen || tocOpen) {
211→        setSettingsOpen(false);
212→        setTocOpen(false);
213→        return;
214→      }
215→
216→      if (footerVisible) {
217→        setFooterVisible(false);
218→        if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
219→      } else {
220→        showFooterTemporarily();
221→      }
222→    },
223→    [footerVisible, settingsOpen, tocOpen, showFooterTemporarily]
224→  );
225→
226→  // Restore scroll position on mount
227→  useEffect(() => {
228→    if (!onRestoreProgress) return;
229→    onRestoreProgress().then((data) => {
230→      if (data && data.scrollPosition > 0) {
231→        window.scrollTo(0, data.scrollPosition);
232→      }
233→    });
234→  }, []);
235→
236→  // Save scroll position (debounced)
237→  useEffect(() => {
238→    if (!onSaveProgress) return;
239→
240→    const handleScroll = () => {
241→      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
242→      saveTimerRef.current = setTimeout(() => {
243→        onSaveProgress({
244→          page: 0,
245→          totalPages: 0,
246→          scrollPosition: window.scrollY,
247→        });
248→      }, 500);
249→    };
250→
251→    window.addEventListener("scroll", handleScroll, { passive: true });
252→    return () => {
253→      window.removeEventListener("scroll", handleScroll);
254→      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
255→    };
256→  }, [onSaveProgress]);
257→
258→  // Save on page unload
259→  useEffect(() => {
260→    if (!onSaveProgress) return;
261→
262→    const handleUnload = () => {
263→      onSaveProgress({
264→        page: 0,
265→        totalPages: 0,
266→        scrollPosition: window.scrollY,
267→      });
268→    };
269→
270→    const handleVisibilityChange = () => {
271→      if (document.visibilityState === "hidden") handleUnload();
272→    };
273→
274→    window.addEventListener("beforeunload", handleUnload);
275→    document.addEventListener("visibilitychange", handleVisibilityChange);
276→    return () => {
277→      window.removeEventListener("beforeunload", handleUnload);
278→      document.removeEventListener("visibilitychange", handleVisibilityChange);
279→    };
280→  }, [onSaveProgress]);
281→
282→  return (
