 1→import { ComponentChildren, ComponentType } from "preact";
 2→
 3→import { ScrollReader } from "./reader/ScrollReader.js";
 4→import { PaginatedReader } from "./reader/PaginatedReader.js";
 5→
 6→export type { ProgressData, ChapterMapData, OfflineProps, ReaderPaywallConfig } from "./reader/types.js";
 7→
 8→export interface ReaderProps {
 9→  children: ComponentChildren;
10→  title: string;
11→  bookTitle?: string;
12→  chapterSlug?: string;
13→  prevChapter?: { slug: string; title: string };
14→  nextChapter?: { slug: string; title: string };
15→  showDropCap?: boolean;
16→  paginationMode?: "scroll" | "paginated";
17→  onSaveProgress?: (data: import("./reader/types.js").ProgressData) => void;
18→  onRestoreProgress?: () => Promise<import("./reader/types.js").ProgressData | null>;
19→  bookProgressPercent?: number;
20→  initialContent?: ComponentType<{ components?: Record<string, unknown> }>;
21→  chapterMapData?: import("./reader/types.js").ChapterMapData;
22→  currentChapterSlug?: string;
23→  allChapters?: Array<{ slug: string; title: string; wordCount?: number }>;
24→  bookBasePath?: string;
25→  onChapterChange?: (slug: string, page: number, totalPages: number) => void;
26→  mdxComponents?: Record<string, unknown>;
27→  paywall?: import("./reader/types.js").ReaderPaywallConfig;
28→  offlineProps?: import("./reader/types.js").OfflineProps;
29→}
30→
31→export function Reader({
32→  children,
33→  bookTitle,
34→  prevChapter,
35→  nextChapter,
36→  showDropCap = true,
37→  paginationMode = "scroll",
38→  onSaveProgress,
39→  onRestoreProgress,
40→  bookProgressPercent,
41→  initialContent,
42→  chapterMapData,
43→  currentChapterSlug,
44→  allChapters,
45→  bookBasePath,
46→  onChapterChange,
47→  mdxComponents,
48→  paywall,
49→  offlineProps,
50→}: ReaderProps) {
51→  if (paginationMode === "paginated") {
52→    return (
53→      <PaginatedReader
54→        bookTitle={bookTitle}
55→        prevChapter={prevChapter}
56→        nextChapter={nextChapter}
57→        showDropCap={showDropCap}
58→        onSaveProgress={onSaveProgress}
59→        onRestoreProgress={onRestoreProgress}
60→        bookProgressPercent={bookProgressPercent}
61→        initialContent={initialContent}
62→        chapterMapData={chapterMapData}
63→        currentChapterSlug={currentChapterSlug}
64→        allChapters={allChapters}
65→        bookBasePath={bookBasePath}
66→        onChapterChange={onChapterChange}
67→        mdxComponents={mdxComponents}
68→        paywall={paywall}
69→        offlineProps={offlineProps}
70→      >
71→        {children}
72→      </PaginatedReader>
73→    );
74→  }
75→
76→  return (
77→    <ScrollReader
78→      bookTitle={bookTitle}
79→      prevChapter={prevChapter}
80→      nextChapter={nextChapter}
81→      showDropCap={showDropCap}
82→      onSaveProgress={onSaveProgress}
83→      onRestoreProgress={onRestoreProgress}
84→      allChapters={allChapters}
85→      bookBasePath={bookBasePath}
86→      currentChapterSlug={currentChapterSlug}
87→      offlineProps={offlineProps}
88→    >
89→      {children}
90→    </ScrollReader>
91→  );
92→}
