This follows the exact guard pattern already used for `PROGRESS_STORE` and `UNLOCKS_STORE`, ensuring safe upgrades.

**3c. Add three bookmark helper functions after `unlockBook` (after line 112)**

```ts
export async function saveBookmark(bookmark: Bookmark): Promise<void> {
  const database = await initDB()
  return new Promise((resolve, reject) => {
    const tx = database.transaction(BOOKMARKS_STORE, 'readwrite')
    const store = tx.objectStore(BOOKMARKS_STORE)
    const request = store.put(bookmark)
    request.onsuccess = () => resolve()
    request.onerror = () => reject(request.error)
  })
}

export async function deleteBookmark(id: string): Promise<void> {
  const database = await initDB()
  return new Promise((resolve, reject) => {
    const tx = database.transaction(BOOKMARKS_STORE, 'readwrite')
    const store = tx.objectStore(BOOKMARKS_STORE)
    const request = store.delete(id)
    request.onsuccess = () => resolve()
    request.onerror = () => reject(request.error)
  })
}

export async function getBookmarksByBook(bookSlug: string): Promise<Bookmark[]> {
  const database = await initDB()
  return new Promise((resolve, reject) => {
    const tx = database.transaction(BOOKMARKS_STORE, 'readonly')
    const store = tx.objectStore(BOOKMARKS_STORE)
    const request = store.getAll()
    request.onsuccess = () => {
      const all = (request.result || []) as Bookmark[]
      resolve(all.filter(b => b.bookSlug === bookSlug).sort((a, b) => b.createdAt - a.createdAt))
    }
    request.onerror = () => reject(request.error)
  })
}
```

