const handleNavigateBookmark = (bookmark: Bookmark) => {
  const targetUrl = `${basePath}/books/${book.slug}/${bookmark.chapterSlug}`
  if (bookmark.chapterSlug === chapterSlug) {
    // Same chapter: restore position directly (via event or scroll)
    // For paginated: could use a callback mechanism
    // For scroll: window.scrollTo
    window.scrollTo(0, bookmark.scrollPosition)
  } else {
    // Cross-chapter: navigate via URL (same pattern as chapter links)
    sessionStorage.setItem('pressy-internal-nav', '1')
    // Store bookmark position for restoration after load
    localStorage.setItem('pressy-bookmark-restore', JSON.stringify({
      chapterSlug: bookmark.chapterSlug,
      page: bookmark.page,
      scrollPosition: bookmark.scrollPosition,
    }))
